  1	import * as React from "react";
  2	import {
  3	  FormGroup,
  4	  MenuToggle,
  5	  MenuToggleElement,
  6	  Select,
  7	  SelectList,
  8	  SelectOption,
  9	} from "@patternfly/react-core";
 10	import { useField } from "formik";
 11	import { getFieldId } from "../../copiedFromConsole/formik-fields/field-utils";
 12	
 13	export type SelectItem = {
 14	  label: string;
 15	  value: string;
 16	};
 17	
 18	const isReactElement = (
 19	  item: SelectItem | React.ReactElement
 20	): item is React.ReactElement => {
 21	  return "props" in item;
 22	};
 23	
 24	export type SelectFieldProps = {
 25	  name: string;
 26	  label?: string;
 27	  isRequired?: boolean;
 28	  items: (SelectItem | React.ReactElement)[];
 29	  isDisabled?: boolean;
 30	};
 31	
 32	const SelectField: React.FC<SelectFieldProps> = ({
 33	  name,
 34	  label,
 35	  isRequired = false,
 36	  items,
 37	  isDisabled = false,
 38	}) => {
 39	  const [{ value }, , { setValue }] = useField(name);
 40	  const [isOpen, setIsOpen] = React.useState(false);
 41	  const fieldId = getFieldId(name, "dropdown");
 42	
 43	  const onToggle = () => {
 44	    setIsOpen(!isOpen);
 45	  };
 46	
 47	  const onSelect = (e, value) => {
 48	    setIsOpen(false);
 49	    setValue(value);
 50	  };
 51	
 52	  const getSelectItems = () => {
 53	    return items.map((item, idx) => {
 54	      if (isReactElement(item)) {
 55	        return item;
 56	      }
 57	      return (
 58	        <SelectOption
 59	          key={idx}
 60	          data-test={`select-${item.label}`}
 61	          value={item.value}
 62	        >
 63	          {item.label}
 64	        </SelectOption>
 65	      );
 66	    });
 67	  };
 68	
 69	  const getToggleLabel = () => {
 70	    const selectItem = items.find(
 71	      (item) => !isReactElement(item) && item.value === value
 72	    ) as SelectItem;
 73	    if (selectItem) {
 74	      return selectItem.label;
 75	    }
 76	    return value;
 77	  };
 78	
 79	  return (
 80	    <FormGroup fieldId={fieldId} label={label} isRequired={isRequired}>
 81	      <Select
 82	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 83	          <MenuToggle
 84	            ref={toggleRef}
 85	            data-test={`toggle-${label}-select`}
 86	            onClick={onToggle}
 87	            isDisabled={isDisabled}
 88	            isExpanded={isOpen}
 89	            isFullWidth
 90	          >
 91	            {getToggleLabel()}
 92	          </MenuToggle>
 93	        )}
 94	        onOpenChange={setIsOpen}
 95	        onSelect={onSelect}
 96	        isOpen={isOpen}
 97	        readOnly={isDisabled}
 98	      >
 99	        <SelectList>{getSelectItems()}</SelectList>
100	      </Select>
101	    </FormGroup>
102	  );
103	};
104	
105	export default SelectField;

